-- Ken's Hardened V2 Fix

local b64_0x11Illl = {}
local char_0xlIlllI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xlllIll=1,#char_0xlIlllI do b64_0x11Illl[char_0xlIlllI:sub(i_0xlllIll,i_0xlllIll)] = i_0xlllIll - 1 end

function b64_0x11Illl.dec_0x1IllII(d_0xIIIIII)
    d_0xIIIIII = string.gsub(d_0xIIIIII, '[^'..char_0xlIlllI..'=]', '')
    local r_0xIIlllI = {}
    for i_0xlllIll=1, #d_0xIIIIII, 4 do
        local c_0xl111ll = b64_0x11Illl[d_0xIIIIII:sub(i_0xlllIll,i_0xlllIll)] or 0
        local c_0x1l1lll = b64_0x11Illl[d_0xIIIIII:sub(i_0xlllIll+1,i_0xlllIll+1)] or 0
        local c_0xIlIlll, c_0xIIl1ll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIIIIII:sub(i_0xlllIll+2,i_0xlllIll+2)
        if ch3 == "=" then has3 = false else c_0xIlIlll = b64_0x11Illl[ch3] or 0 end
        local ch4 = d_0xIIIIII:sub(i_0xlllIll+3,i_0xlllIll+3)
        if ch4 == "=" then has4 = false else c_0xIIl1ll = b64_0x11Illl[ch4] or 0 end
        local b_0xlIIlIl = c_0xl111ll * (2^18) + c_0x1l1lll * (2^12) + c_0xIlIlll * (2^6) + c_0xIIl1ll
        local b_0xIllllI = math.floor(b_0xlIIlIl / (2^16)) % (2^8)
        local b_0xIl11II = math.floor(b_0xlIIlIl / (2^8)) % (2^8)
        local b_0x1llIll = b_0xlIIlIl % (2^8)
        table.insert(r_0xIIlllI, string.char(b_0xIllllI))
        if has3 then table.insert(r_0xIIlllI, string.char(b_0xIl11II)) end
        if has4 then table.insert(r_0xIIlllI, string.char(b_0x1llIll)) end
    end
    return table.concat(r_0xIIlllI)
end


local function bxor_0xll1llI(a_0xIl1ll1,b_0xI1IlII)
    if bit32 then return bit32.bxor(a_0xIl1ll1,b_0xI1IlII) end
    local r_0xI1lII1 = 0
    for i_0xI1IlI1 = 0, 7 do
        local x_0xII1I1l = a_0xIl1ll1 % 2
        local y_0xlll1Il = b_0xI1IlII % 2
        if x_0xII1I1l ~= y_0xlll1Il then r_0xI1lII1 = r_0xI1lII1 + (2^i_0xI1IlI1) end
        a_0xIl1ll1 = math.floor(a_0xIl1ll1 / 2)
        b_0xI1IlII = math.floor(b_0xI1IlII / 2)
    end
    return r_0xI1lII1
end


local function bxor_str_0xl1ll1I(s_0xl1llIl, k_0x1Illll)
    local r_0xlIlIll = {}
    for i_0xIIIl1l=1, #s_0xl1llIl do
        local b_0x1III1I = string.byte(s_0xl1llIl, i_0xIIIl1l)
        local kb_0xlllllI = string.byte(k_0x1Illll, (i_0xIIIl1l-1) % #k_0x1Illll + 1)
        r_0xlIlIll[i_0xIIIl1l] = string.char(bxor_0xll1llI(b_0x1III1I, kb_0xlllllI))
    end
    return table.concat(r_0xlIlIll)
end


local function getkeys_0xllIllI()
    local seed = b64_0x11Illl.dec_0x1IllII("ZGU4aW5PT3k=")
    local k1_enc = b64_0x11Illl.dec_0x1IllII("AgBLLyguNSw=")
    local k2_enc = b64_0x11Illl.dec_0x1IllII("XDZ7B1h9eTA=")
    return bxor_str_0xl1ll1I(k1_enc, seed), bxor_str_0xl1ll1I(k2_enc, seed)
end


local function cff_0xIll1lI(a_0xlIIIII)
    local st_0x1I1IlI = 0
    local res_0xlI1ll1 = a_0xlIIIII
    while true do
        if st_0x1I1IlI == 0 then
            res_0xlI1ll1 = res_0xlI1ll1 + 1
            st_0x1I1IlI = 1
        elseif st_0x1I1IlI == 1 then
            res_0xlI1ll1 = res_0xlI1ll1 * 2
            st_0x1I1IlI = 2
        elseif st_0x1I1IlI == 2 then
            res_0xlI1ll1 = res_0xlI1ll1 - 3
            st_0x1I1IlI = 3
        else
            break
        end
    end
    return res_0xlI1ll1
end


local function chain_0x11lIll(x) return x*2 end
local function chain_0xlIIllI(x) return chain_0x11lIll(x)+1 end


local d_0x1l1IIl = {
  {op=255, val="", is_enc=true},
}
local pc_0xIIII11 = 1
local stk_0x1llIll = {}
stk_0x1llIll._jmp = nil


local disp_0xIllI1I = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xllIllI()

local state_0xllIlII = 0
while true do
    if state_0xllIlII == 0 then  -- FETCH
        if pc_0xIIII11 > #d_0x1l1IIl then break end
        local inst = d_0x1l1IIl[pc_0xIIII11]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0x11Illl.dec_0x1IllII(val)
            d = bxor_str_0xl1ll1I(d, k2)
            val = bxor_str_0xl1ll1I(d, k1)
        end
        stk_0x1llIll._jmp = nil
        pc_0xIIII11 = pc_0xIIII11 + 1
        cur_op_0xlIl1l1 = opcode
        cur_val_0xllIlll = val
        state_0xllIlII = 1

    elseif state_0xllIlII == 1 then  -- EXECUTE
        local handler = disp_0xIllI1I[cur_op_0xlIl1l1]
        if handler then
            handler(stk_0x1llIll, cur_val_0xllIlll)
        end
        if stk_0x1llIll._jmp then
            pc_0xIIII11 = pc_0xIIII11 + stk_0x1llIll._jmp
        end
        state_0xllIlII = 0
    else
        break
    end
end
